```python
def check_date(year, month, day):
    # تحقق من أن التاريخ يتكون من ثلاثة أرقام
    if not (isinstance(year, int) and isinstance(month, int) and isinstance(day, int)):
        return False

    # تحقق من أن يومًا بين 1 و 31
    if not (1 <= day <= 31):
        return False

    # تحقق من أن شهرًا بين 1 و 12
    if not (1 <= month <= 12):
        return False

    # تحقق من أن شهرة بين 1000 و 9999
    if not (1000 <= year <= 9999):
        return False

    # تحقق من أن شهرة منفصلة
    if year % 4 == 0 and (year % 100 != 0 or year % 400 == 0):
        if month in [1, 3, 5, 7, 8, 10, 12]:
            return day <= 31
        elif month == 2:
            return day <= 29
        else:
            return day <= 30
    else:
        if month in [1, 3, 5, 7, 8, 10, 12]:
            return day <= 31
        elif month == 2:
            return day <= 28
        else:
            return day <= 30

    # إذا تمت الموافقة على جميع المتطلبات، فيرجع True
    return True
```

هذه الدالة `check_date` تحقق صحة التاريخ الغريغوري. يمكن استدعاؤها بسهولة مع ثلاثة أرقام: يوم، شهر، وشهرة.

