def solve(arr):
    # احسب عدد التبديلات في المصفوفة
    def count_inversions(arr):
        # احسب عدد التبديلات باستخدام تقنية ميرسون
        count = 0
        for i in range(len(arr)):
            for j in range(i + 1, len(arr)):
                if arr[i] > arr[j]:
                    count += 1
        return count

    # احسب عدد التبديلات للنوع الأول
    type1_count = count_inversions(arr)

    # احسب عدد التبديلات للنوع الثاني
    type2_count = count_inversions([x for x in arr if x % 2 == 0])

    # احسب عدد التبديلات للنوع الثالث
    type3_count = count_inversions([x for x in arr if x % 2 != 0])

    # قم بتحليل النتائج
    if type1_count == type2_count and type1_count == type3_count:
        return "النتائج متطابقة"
    elif type1_count == type2_count:
        return "النتائج متطابقة للنوعين الأول والثاني"
    elif type1_count == type3_count:
        return "النتائج متطابقة للنوعين الأول والثالث"
    elif type2_count == type3_count:
        return "النتائج متطابقة للنوعين الثاني والثالث"
    else:
        return "النتائج غير متطابقة"

# اختبار الوظيفة
print(solve([1, 2, 3, 4, 5, 6, 7, 8, 9]))
