def rearange_string(s):
    # إنشاء قائمة من الأقوام الموجودة في السلسلة
    char_count = {}
    for char in s:
        if char in char_count:
            char_count[char] += 1
        else:
            char_count[char] = 1

    # إنشاء قائمة من الأقوام التي تكررت أكثر من مرة
    repeated_chars = [char for char, count in char_count.items() if count > 1]

    # إذا كان عدد الأقوام التي تكررت أكثر من مرة أكبر من 2، فيعني أننا لا نستطيع ترتيب الأقوام بحيث تكون الأقوام المجاورة مختلفة
    if len(repeated_chars) > 2:
        return False

    # إذا كان عدد الأقوام التي تكررت أكثر من مرة يساوي 2، فيعني أننا نستطيع ترتيب الأقوام بحيث تكون الأقوام المجاورة مختلفة
    if len(repeated_chars) == 2:
        # إذا كان مجموع عدد مرات تكرار الأقوام التي تكررت أكثر من مرة أكبر من أو يساوي عدد أحرف السلسلة، فيعني أننا لا نستطيع ترتيب الأقوام بحيث تكون الأقوام المجاورة مختلفة
        if sum(char_count[char] for char in repeated_chars) >= len(s):
            return False

    # إذا لم يكن هناك أي أعداد تكررت أكثر من مرة، فيعني أننا نستطيع ترتيب الأقوام بحيث تكون الأقوام المجاورة مختلفة
    return True
```

