def convert_list_dictionary(*lists):
    # إذا كان عدد القوائم غير متساوي، فلا يمكن تحويلها إلى قاموس متداخل
    if len(lists) == 0:
        return {}
    elif len(lists) == 1:
        return {i: value for i, value in enumerate(lists[0])}
    else:
        # تحديد العنصر الأول في القائمة الأولى كключ في القاموس
        key = lists[0][0]

        # إنشاء قاموس جديد
        nested_dict = {}

        # إنشاء قوائم جديدة من العناصر في القوائم الأخرى باستثناء العنصر الأول
        new_lists = [lst[1:] for lst in lists[1:]]

        # إنشاء قاموس متداخل باستخدام العنصر الأول في القائمة الأولى كключ
        nested_dict[key] = convert_list_dictionary(*new_lists)

        return nested_dict
```

