def get_odd_occurence(arr):
    # إنشاء قاموس للاحتفاظ بالتكرارات
    count_dict = {}

    # إجراء دورة على المصفوفة
    for num in arr:
        # إذا كان العدد موجودًا في القاموس، زيادة التكرار
        if num in count_dict:
            count_dict[num] += 1
        # إذا لم يكن العدد موجودًا في القاموس، إضافة العدد مع تكرار واحد
        else:
            count_dict[num] = 1

    # إجراء دورة على القاموس
    for num, count in count_dict.items():
        # إذا كان التكرار غير زوجي، عائد العدد
        if count % 2 != 0:
            return num

    # إذا لم يكن هناك عدد يحدث بشكل غير زوجي، عائد -1
    return -1
```

