def first_non_repeating_character(s):
    # إنشاء قاموس لتحصيل تكرار كل حرف في السلسلة
    char_count = {}

    # تحليل كل حرف في السلسلة
    for char in s:
        # إذا كان الحرف موجودًا بالفعل في القاموس، زيادة عدد مرات ظهوره
        if char in char_count:
            char_count[char] += 1
        # إذا لم يكن الحرف موجودًا في القاموس، إضافته مع عدد مرات ظهوره
        else:
            char_count[char] = 1

    # تحليل كل حرف في السلسلة مرة أخرى
    for char in s:
        # إذا كان عدد مرات ظهور الحرف هو 1، عائد به
        if char_count[char] == 1:
            return char

    # إذا لم يكن هناك أي حرف غير مكرر، عائد ب None
    return None
