def is_Product_Even(numbers):
    # حدد الدالة التي ستقوم بتحليل قائمة الأرقام
    def analyze_numbers(numbers):
        # استخدم حلقة لمراجعة كل رقم في القائمة
        for num in numbers:
            # إذا كان الرقم غير صحيحًا، فلا يمكن أن يكون المنتج صحيحًا
            if not isinstance(num, (int, float)):
                return False
        # إذا لم يكن هناك أي رقم غير صحيح، فاستخدم حلقة لمراجعة كل رقم في القائمة
        for num in numbers:
            # إذا كان الرقم غير منتهي، فلا يمكن أن يكون المنتج صحيحًا
            if num % 1 != 0:
                return False
        # إذا لم يكن هناك أي رقم غير منتهي، فاستخدم حلقة لمراجعة كل رقم في القائمة
        for num in numbers:
            # إذا كان الرقم منتهيًا، فاستخدمه في الحساب
            if num % 2 == 0:
                return True
        # إذا لم يكن هناك أي رقم منتهي، فلا يمكن أن يكون المنتج منتهيًا
        return False

    # استخدم حلقة لمراجعة كل رقم في القائمة
    for num in numbers:
        # إذا كان الرقم منتهيًا، فاستخدمه في الحساب
        if num % 2 == 0:
            # استخدم حلقة لمراجعة كل رقم في القائمة
            for other_num in numbers:
                # إذا كان الرقم الآخر منتهيًا، فاستخدمه في الحساب
                if other_num % 2 == 0:
                    # إذا كان المنتج منتهيًا، فارجع القيمة الصحيحة
                    return True
    # إذا لم يكن المنتج منتهيًا، فارجع القيمة الخاطئة
    return False
```

هذه الدالة `is_Product_Even` تقوم بتحليل قائمة الأرقام وتحديد ما إذا كان المنتج منتهيًا أم لا. الدالة `analyze_numbers` هي دالة مساعدة تستخدم في تحليل القائمة.

