def text_match_string(text, pattern):
    # تحقق إذا كان النص والنمط غير فارغين
    if not text or not pattern:
        return False

    # تحقق إذا كان النمط يبدأ بالحرف الأول للنص
    if text[0] != pattern[0]:
        return False

    # إذا كان النمط يحتوي على أكثر من حرف، فحسّن البحث في النص
    if len(pattern) > 1:
        # استدعاء الدالة التكرارية نفسها مع النص المتبقي والنمط المتبقي
        return text_match_string(text[1:], pattern[1:])

    # إذا تم العثور على تطابق، فارجع True
    return True
```

هذه الدالة `text_match_string` تقوم بتحديد ما إذا كان النمط يبدأ بالحرف الأول للنص أم لا. إذا كان النمط يحتوي على أكثر من حرف، فستستدعى نفسها تكرارًا مع النص المتبقي والنمط المتبقي. إذا تم العثور على تطابق، فسترجع `True`.

```python
def get_Pairs_Count(arr, sum):
    # قم بتحويل المصفوفة إلى قاموس لتحسين سرعة البحث
    arr_dict = {}
    for num in arr:
        # إذا كان القيمة موجودة في القاموس، قم بزيادة قيمة المفتاح
        if num in arr_dict:
            arr_dict[num] += 1
        # إذا لم تكن القيمة موجودة في القاموس، قم بإضافتها مع قيمة 1
        else:
            arr_dict[num] = 1

    # قم بتحديد عدد الزوجيات التي يمكن أن تصل قيمتها إلى 'sum'
    count = 0
    for num in arr_dict:
        # إذا كان المفتاح موجود في القاموس، قم بتحديد قيمة المفتاح
        if num in arr_dict:
            # إذا كان المفتاح أقل من 'sum'، قم بزيادة العدد بالفرق بين 'sum' والمفتاح
            if num < sum:
                count += arr_dict[sum - num]
            # إذا كان المفتاح يساوي 'sum'، قم بزيادة العدد بالربع من قيمة المفتاح
            elif num == sum:
                count += arr_dict[num] // 2
            # إذا كان المفتاح أكبر من 'sum'، قم بزيادة العدد بالفرق بين المفتاح و'sum'
            else:
                count += arr_dict[num]

    # قم بارجاع العدد
    return count
```

هذه الدالة `get_Pairs_Count` تقوم بتحديد عدد الزوجيات في المصفوفة `arr` التي يمكن أن تصل قيمتها إلى `sum`. الدالة تعمل على تحويل المصفوفة إلى قاموس لتحسين سرعة البحث، ثم تقوم بتحديد عدد الزوجيات التي يمكن أن تصل قيمتها إلى `sum` عن طريق إجراء عملية البحث في القاموس.

```python
def get_Odd_Occurrence(nums):
    # إنشاء قاموس لتحديد عدد مرات ظهور كل عنصر في القائمة
    count_dict = {}

    # تحديد عدد مرات ظهور كل عنصر في القائمة
    for num in nums:
        if num in count_dict:
            count_dict[num] += 1
        else:
            count_dict[num] = 1

    # تحديد العنصر الذي يظهر عدد مرات غير زوجية
    odd_occurrence = None
    for num, count in count_dict.items():
        if count % 2 != 0:
            odd_occurrence = num
            break

    return odd_occurrence

# مثال على استخدام الوظيفة
print(get_Odd_Occurrence([1, 2, 3, 2, 1]))  # Output: 3
