def max_of_three(a, b, c):
    # أولاً: يجب أن نضمن أننا نستقبل ثلاثة أرقام
    if not isinstance(a, (int, float)) or not isinstance(b, (int, float)) or not isinstance(c, (int, float)):
        raise ValueError("يجب أن تكون جميع الأرقام من النوع العددي")

    # ثانياً: يجب أن نضمن أن الأرقام غير سالبة
    if a <= 0 or b <= 0 or c <= 0:
        raise ValueError("يجب أن تكون جميع الأرقام إيجابية")

    # ثالثاً: يمكننا الآن استخدام وظيفة max() لتحديد أكبر رقم
    return max(a, b, c)
```

