print(dif_Square(25))  # True
print(dif_Square(26))  # False
print(dif_Square(-25)) # True
print(dif_Square(0))   # True
```

```python
def are_Rotations(s1, s2):
    # إذا كان طول السلسلة الأولى أكبر من السلسلة الثانية، فلا يمكن أن تكون السلسلتان دورانًا لبعضهما البعض
    if len(s1) > len(s2):
        return False

    # إذا كان طول السلسلة الأولى أقل من السلسلة الثانية، فلا يمكن أن تكون السلسلتان دورانًا لبعضهما البعض
    if len(s1) < len(s2):
        return False

    # إذا كانت السلسلتان متساويتان، فلا يمكن أن تكون السلسلتان دورانًا لبعضهما البعض
    if s1 == s2:
        return False

    # إذا كانت السلسلتان متساويتان، فلا يمكن أن تكون السلسلتان دورانًا لبعضهما البعض
    if s1 + s1 == s2:
        return True

    # إذا كانت السلسلتان متساويتان، فلا يمكن أن تكون السلسلتان دورانًا لبعضهما البعض
    if s2 + s2 == s1:
        return True

    # إذا لم تكن السلسلتان متساويتان، فحاول أن تجرب دوران السلسلة الأولى
    for i in range(len(s1)):
        # إذا كانت السلسلة الثانية متساوية مع دوران السلسلة الأولى، فلا يمكن أن تكون السلسلتان دورانًا لبعضهما البعض
        if s1[i:] + s1[:i] == s2:
            return True

    # إذا لم تكن السلسلتان دورانًا لبعضهما البعض، فارجع False
    return False
```

هذه الدالة `are_Rotations` تقوم بتحديد ما إذا كانت السلسلتان `s1` و `s2` دورانًا لبعضهما البعض أم لا. الدالة تعمل على أساس أن السلسلتان تكون دورانًا لبعضهما البعض إذا كانت السلسلة الأولى متساوية مع دوران السلسلة الثانية.

