def start_withp(words):
    # تحقق إذا كان القائمة غير فارغة
    if not words:
        return False

    # تحقق إذا كان كل كلمة في القائمة تبدأ بحرف 'p'
    if all(word.lower().startswith('p') for word in words):
        # إذا كان كل كلمة تبدأ بحرف 'p'، فحاول أن تجد كلمتين متطابقتين
        for i in range(len(words)):
            for j in range(i + 1, len(words)):
                if words[i] == words[j]:
                    return True
    return False
```

يمكن استخدام هذه الدالة كما يلي:

```python
words = ['python', 'pascal', 'perl', 'pascal']
print(start_withp(words))  # Output: True
```

في هذه الحالة، الدالة `start_withp` تعيد `True` لأن كلمتي 'pascal' متطابقتان في القائمة.

إذا أردت أن تحدد كلمتين متطابقتين من القائمة، يمكنك استخدام الدالة `start_withp` مع بعض التعديلات. يمكنك استخدام قائمتين من الكلمات، واحدة للقائمة الأصلية والもう أخرى للقائمة المحددة. ثم يمكنك استخدام الدالة `set` لتحديد الكلمات الموجودة في القائمة الأصلية ولكن غير موجودة في القائمة المحددة.

```python
def start_withp(words, target_words):
    # تحقق إذا كان القائمة غير فارغة
    if not words:
        return False

    # تحقق إذا كان كل كلمة في القائمة تبدأ بحرف 'p'
    if all(word.lower().startswith('p') for word in words):
        # تحقق إذا كان كل كلمة في القائمة المحددة موجودة في القائمة الأصلية
        if set(words).issuperset(set(target_words)):
            # إذا كان كل كلمة في القائمة المحددة موجودة في القائمة الأصلية، فحاول أن تجد كلمتين متطابقتين
            for i in range(len(words)):
                for j in range(i + 1, len(words)):
                    if words[i] == words[j]:
                        return True
    return False
```

