def drop_empty(dictionary):
    # نبدأ بتحديد الدالة drop_empty التي تتطلب كلمة مفتاح من النوع dictionary
    # هذه الدالة ستقوم بتحديد العناصر الفارغة في القائمة المفتوحة
    # وستقوم بإزالتها من القائمة المفتوحة

    # نبدأ بتحديد القائمة المفتوحة التي سنقوم بإزالة العناصر الفارغة منها
    new_dict = {}

    # نستخدم حلقة لمرور على كل عنصر في القائمة المفتوحة
    for key, value in dictionary.items():
        # نتحقق إذا كان القيمة غير فارغة
        if value:
            # إذا كانت القيمة غير فارغة، نضيفها إلى القائمة الجديدة
            new_dict[key] = value

    # نعود القيمة الجديدة للقائمة المفتوحة
    return new_dict

# نستخدم الدالة drop_empty لتحديد القائمة المفتوحة الجديدة
