def add_dict(dict1, dict2):
    # إنشاء نسخة من الديكشنري الأول لمنع تغيير القيم الأصلية
    result = dict1.copy()

    # استعراض قيم الديكشنري الثاني
    for key, value in dict2.items():
        # إذا كان المفتاح موجودًا في الديكشنري الأول، قم بزيادة القيمة
        if key in result:
            # إضافة القيمة إلى القيمة الموجودة بالفعل
            result[key] += value
        else:
            # إذا لم يكن المفتاح موجودًا، قم بضافته إلى النتيجة
            result[key] = value

    # عودة النتيجة
    return result
```

