```python
def min_of_three(a, b, c):
    # أولاً: يجب أن نضمن أن جميع الأرقام واردة
    if not (isinstance(a, (int, float)) and isinstance(b, (int, float)) and isinstance(c, (int, float))):
        raise ValueError("جميع الأرقام يجب أن تكون من النوع العددي")

    # ثانياً: يجب أن نضمن أن جميع الأرقام مختلفة
    if a == b == c:
        raise ValueError("جميع الأرقام يجب أن تكون مختلفة")

    # ثالثاً: يمكننا الآن استخدام وظيفة min() لتحديد الأقل من الأرقام الثلاثة
    return min(a, b, c)
```

هذا الكود يحتوي على وظيفة `min_of_three` التي تتطلب ثلاثة أرقام كمعاملات. أولاً، يضمن أن جميع الأرقام واردة ومتطابقة مع النوع العددي. ثانياً، يضمن أن جميع الأرقام مختلفة. ثالثاً، يستخدم وظيفة `min()` لتحديد الأقل من الأرقام الثلاثة.

```python
def length_Of_Last_Word(s):
    # نبدأ بتحويل الكلمة إلى قائمة من كلمات
    words = s.split()

    # نتحقق إذا كانت القائمة فارغة
    if not words:
        # إذا كانت فارغة، فإن الطول هو 0
        return 0

    # نتحقق إذا كانت القائمة تحتوي على أكثر من كلمة
    if len(words) > 1:
        # إذا كانت تحتوي على أكثر من كلمة، فإن الطول هو الطول الأخير
        return len(words[-1])

    # إذا كانت القائمة تحتوي على كلمة واحدة فقط، فإن الطول هو الطول الكلي للكلمة
    return len(words[0])
```

يمكننا أيضًا استخدام طريقة أخرى أكثر فعالية:

```python
def length_Of_Last_Word(s):
    # نتحقق إذا كانت الكلمة فارغة
    if not s:
        # إذا كانت فارغة، فإن الطول هو 0
        return 0

    # نتحقق إذا كانت الكلمة تحتوي على مسافة في نهايتها
    if s[-1] == ' ':
        # إذا كانت تحتوي على مسافة في نهايتها، فإن الطول هو الطول الكلي للكلمة دون المسافة
        return len(s) - s.rfind(' ')

    # إذا كانت الكلمة تحتوي على مسافة في منتصفها، فإن الطول هو الطول الكلي للكلمة
    return len(s)
```

في هذه الطريقة، نستخدم `s.rfind(' ')` لتحديد آخر مكان للفاصلة في الكلمة. ثم نضيف 1 إلى هذا الموقع لتحديد الطول الكلي للكلمة دون الفاصلة.

```python
def is_Isomorphic(str1, str2):
    # إذا كان طول السلسلتين غير متساوٍ، فهما لا يمكن أن تكونا متشابهتين
    if len(str1) != len(str2):
        return False

    # إنشاء قاموسين للاحتفاظ بالعلاقة بين الحروف في السلسلتين
    mapping1 = {}
    mapping2 = {}

    # تحقق من كل حرف في السلسلة الأولى
    for char1, char2 in zip(str1, str2):
        # إذا كان الحرف في السلسلة الأولى موجودًا بالفعل في القائمة، فإنه يجب أن يكون متطابقًا مع الحرف في السلسلة الثانية
        if char1 in mapping1 and mapping1[char1] != char2:
            return False
        # إذا كان الحرف في السلسلة الثانية موجودًا بالفعل في القائمة، فإنه يجب أن يكون متطابقًا مع الحرف في السلسلة الأولى
        if char2 in mapping2 and mapping2[char2] != char1:
            return False
        # إضافة الحرفين إلى القوائم
        mapping1[char1] = char2
        mapping2[char2] = char1

    # إذا لم يكن هناك أي حالات غير متطابقة، فهما متشابهتان
    return True
```

هذه الدالة `is_Isomorphic` تقوم بتحليل السلسلتين `str1` و `str2` وتحديد ما إذا كانت متشابهتان أم لا. إذا كانت السلسلتان متشابهتان، فإنها تعيد `True`، وإلا تعيد `False`.
